                "url": "https://rerai.umntwana.app/sites/zimbabwe/files/styles/content_1200xh_/public/2021-08/safely-exploring-objects.webp?itok=wzlNam0H",
                "name": "Safely%20Exploring%20Objects.jpg",
                "alt": "A baby with a tissue in her or his mouth"
