                "url": "https://rerai.umntwana.app/sites/zimbabwe/files/styles/content_1200xh_/public/2021-08/making-food-for-my-family-cover-picture.webp?itok=U6PmgBsJ",
                "name": "Making%20Food%20for%20My%20Family-cover-picture.jpg",
                "alt": "A child helping to prepare the meal"
